Bash(cd "D:\\projects\\XSALE\\XSaleFrontend" && node -e "
const fs = require\('fs'\);
const data = JSON.parse\(fs.readFileSync\('XSale full application flow.excalidraw', 'utf8'\)\);
const elements = data.elements;

const texts = elements.filter\(e => e.type === 'text' && !e.isDeleted\);
const arrows = elements.filter\(e => e.type === 'arrow' && !e.isDeleted\);
const images = elements.filter\(e => e.type === 'image' && !e.isDeleted\);

console.log\('=== TEXTS \(sorted by y then x\) ==='\);
texts.sort\(\(a,b\) => a.y - b.y || a.x - b.x\).forEach\(e => {
  console.log\('[' + Math.round\(e.x\) + ', ' + Math.round\(e.y\) + '] \\"' + e.text.replace\(/\\n/g,' | '\) + '\\"'\);
}\);

console.log\('\\n=== IMAGE IDs \(for reference\) ==='\);
images.forEach\(e => {
  const bound = e.boundElements || [];
  console.log\('ID:' + e.id + ' pos:[' + Math.round\(e.x\) + ',' + Math.round\(e.y\) + '] size:[' + Math.round\(e.width\) + 'x' + Math.round\(e.height\) + '] arrows:' + bound.map\(b=>b.id\).join\(','\)\);
}\);

console.log\('\\nTotal: texts=' + texts.length + ' arrows=' + arrows.length + ' images=' + images.length\);
")
